// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/// @title CommunityLPVaultFOTInit — Fee-on-transfer (taxed-token) variant of CommunityLPVaultV3Init
/// @notice IDENTICAL mechanics to CommunityLPVaultV3Init (clone-compatible, initialize()-based,
///         same charity-mint → swap → addLiquidity → LP-share flow) with ONE class of fix:
///         the community TOKEN may charge a transfer tax (e.g. Midas ~2%). USDC and the Money
///         (FUND) token are standard ERC20s and are NOT taxed; only TOKEN is.
///
///         Every inbound TOKEN movement is accounted by the ACTUAL balance delta
///         (balanceOf after − before), never by the requested/quoted amount. TOKEN swaps use
///         swapExactTokensForTokensSupportingFeeOnTransferTokens. addLiquidity is always called
///         with the TOKEN amount the vault truly holds, so the router never tries to pull more
///         TOKEN than is present (the bug that makes the clean vault revert with
///         TransferHelper: TRANSFER_FROM_FAILED on taxed tokens).
///
///         IMPORTANT (operator): because TOKEN swap output arrives post-tax, the per-swap
///         min-output (derived from maxImpactBps) must leave room for the tax. Deploy these
///         vaults with maxImpactBps >= token transfer tax + slippage headroom (e.g. a 2% tax
///         wants maxImpactBps >= ~400–600). See _minOutput note below.

interface IERC20 {
    function approve(address, uint256) external returns (bool);
    function balanceOf(address) external view returns (uint256);
    function transfer(address, uint256) external returns (bool);
    function transferFrom(address, address, uint256) external returns (bool);
}

interface ICharityFund {
    function deposit(uint256) external;
    function redeem(uint256) external;
    function claimV2Pool(address pool, address lpHolder) external;
}

interface IUniswapV2Router02 {
    function addLiquidity(address, address, uint256, uint256, uint256, uint256, address, uint256)
        external returns (uint256, uint256, uint256);
    function removeLiquidity(address, address, uint256, uint256, uint256, address, uint256)
        external returns (uint256, uint256);
    // Fee-on-transfer-safe swap: returns nothing; recipient must measure its own balance delta.
    function swapExactTokensForTokensSupportingFeeOnTransferTokens(
        uint256, uint256, address[] calldata, address, uint256
    ) external;
}

interface IUniswapV2Pair {
    function getReserves() external view returns (uint112, uint112, uint32);
    function token0() external view returns (address);
}

contract CommunityLPVaultFOTInit {

    // ── State (set in initialize, not immutable) ─────────────
    address public USDC;
    address public FUND;
    address public TOKEN;
    address public LP;
    ICharityFund public charityFund;
    IUniswapV2Router02 public v2Router;
    bool public fundIsToken0;
    address public owner;

    // ── Config ──────────────────────────────────────────────
    uint256 public maxImpactBps;
    uint256 public constant MAX_IMPACT_CAP = 1500;

    // ── LP Shares ───────────────────────────────────────────
    uint256 public totalShares;
    mapping(address => uint256) public shares;

    // ── Pending Deposits ────────────────────────────────────
    mapping(address => uint256) public pendingDeposit;
    uint256 public totalPendingDeposit;

    // ── Init guard ──────────────────────────────────────────
    bool private _initialized;

    // ── Reentrancy ──────────────────────────────────────────
    uint256 private _locked;
    modifier nonReentrant() {
        require(_locked == 1, "reentrant");
        _locked = 2;
        _;
        _locked = 1;
    }

    // ── Events ──────────────────────────────────────────────
    event Deposited(address indexed user, uint256 shares, uint256 usdcIn);
    event DepositQueued(address indexed user, uint256 usdcAmount);
    event DepositCancelled(address indexed user, uint256 usdcAmount);
    event Withdrawn(address indexed user, uint256 shares, uint256 amountOut, bool asToken);
    event Compounded(address indexed caller, uint256 fundUsed, uint256 lpAdded);
    event Donated(address indexed donor, uint256 usdcAmount, uint256 lpAdded);
    event MaxImpactChanged(uint256 oldBps, uint256 newBps);

    // ═════════════════════════════════════════════════════════
    //  Initialize (replaces constructor for clones)
    // ═════════════════════════════════════════════════════════

    function initialize(
        address _usdc,
        address _fund,
        address _token,
        address _lp,
        address _v2Router,
        uint256 _maxImpactBps,
        address _owner
    ) external {
        require(!_initialized, "already initialized");
        require(_maxImpactBps > 0 && _maxImpactBps <= MAX_IMPACT_CAP, "invalid impact");
        _initialized = true;
        _locked = 1;

        USDC       = _usdc;
        FUND       = _fund;
        TOKEN      = _token;
        LP         = _lp;
        charityFund = ICharityFund(_fund);
        v2Router   = IUniswapV2Router02(_v2Router);
        maxImpactBps = _maxImpactBps;
        owner      = _owner;
        fundIsToken0 = IUniswapV2Pair(_lp).token0() == _fund;

        IERC20(_usdc).approve(_fund, type(uint256).max);
        IERC20(_fund).approve(_v2Router, type(uint256).max);
        IERC20(_token).approve(_v2Router, type(uint256).max);
    }

    // ═════════════════════════════════════════════════════════
    //  Config
    // ═════════════════════════════════════════════════════════

    function setMaxImpact(uint256 bps) external {
        require(msg.sender == owner, "not owner");
        require(bps > 0 && bps <= MAX_IMPACT_CAP, "invalid");
        emit MaxImpactChanged(maxImpactBps, bps);
        maxImpactBps = bps;
    }

    // ═════════════════════════════════════════════════════════
    //  COMPOUND — claim charity yield, deepen LP for all holders
    // ═════════════════════════════════════════════════════════

    function compound() external nonReentrant {
        require(totalShares > 0, "no depositors");
        try charityFund.claimV2Pool(LP, address(this)) {} catch {}
        uint256 fundBal = IERC20(FUND).balanceOf(address(this));
        require(fundBal > 0, "nothing to compound");
        uint256 halfFund = fundBal / 2;
        require(halfFund > 0, "amount too small");

        // FUND -> TOKEN (FOT-safe): measure the TOKEN actually received.
        uint256 tokenForLP = _swapFundToToken(halfFund);

        uint256 fundForLP = fundBal - halfFund;
        (,, uint256 lpAdded) = v2Router.addLiquidity(
            FUND, TOKEN, fundForLP, tokenForLP, 0, 0, address(this), block.timestamp
        );
        emit Compounded(msg.sender, fundBal, lpAdded);
    }

    function donate(uint256 usdcAmount) external nonReentrant {
        require(usdcAmount > 0, "zero");
        require(totalShares > 0, "no depositors");
        _safeTransferFrom(USDC, msg.sender, address(this), usdcAmount);
        uint256 lp = _buildLP(usdcAmount);
        emit Donated(msg.sender, usdcAmount, lp);
    }

    // ═════════════════════════════════════════════════════════
    //  INSTANT DEPOSIT
    // ═════════════════════════════════════════════════════════

    function deposit(uint256 usdcAmount) external nonReentrant {
        require(usdcAmount > 0, "zero");
        _safeTransferFrom(USDC, msg.sender, address(this), usdcAmount);

        uint256 fundBefore = IERC20(FUND).balanceOf(address(this));
        uint256 tokenBefore = IERC20(TOKEN).balanceOf(address(this));

        uint256 lp = _buildLP(usdcAmount);
        shares[msg.sender] += lp;
        totalShares += lp;

        _returnOperationDust(msg.sender, fundBefore, tokenBefore);
        emit Deposited(msg.sender, lp, usdcAmount);
    }

    // ═════════════════════════════════════════════════════════
    //  QUEUED DEPOSIT
    // ═════════════════════════════════════════════════════════

    function depositQueued(uint256 usdcAmount) external nonReentrant {
        require(usdcAmount > 0, "zero");
        _safeTransferFrom(USDC, msg.sender, address(this), usdcAmount);
        pendingDeposit[msg.sender] += usdcAmount;
        totalPendingDeposit += usdcAmount;
        emit DepositQueued(msg.sender, usdcAmount);
    }

    function processDeposit(address user, uint256 usdcAmount) external nonReentrant {
        require(usdcAmount > 0 && usdcAmount <= pendingDeposit[user], "bad amount");
        pendingDeposit[user] -= usdcAmount;
        totalPendingDeposit -= usdcAmount;

        uint256 fundBefore = IERC20(FUND).balanceOf(address(this));
        uint256 tokenBefore = IERC20(TOKEN).balanceOf(address(this));

        uint256 lp = _buildLP(usdcAmount);
        shares[user] += lp;
        totalShares += lp;

        _returnOperationDust(user, fundBefore, tokenBefore);
        emit Deposited(user, lp, usdcAmount);
    }

    function cancelDeposit(uint256 usdcAmount) external nonReentrant {
        require(usdcAmount > 0 && usdcAmount <= pendingDeposit[msg.sender], "bad amount");
        pendingDeposit[msg.sender] -= usdcAmount;
        totalPendingDeposit -= usdcAmount;
        _safeTransfer(USDC, msg.sender, usdcAmount);
        emit DepositCancelled(msg.sender, usdcAmount);
    }

    // ═════════════════════════════════════════════════════════
    //  WITHDRAW
    // ═════════════════════════════════════════════════════════

    function withdraw(uint256 shareAmount) external nonReentrant {
        _doWithdraw(msg.sender, shareAmount, false);
    }

    function withdrawAsToken(uint256 shareAmount) external nonReentrant {
        _doWithdraw(msg.sender, shareAmount, true);
    }

    // ═════════════════════════════════════════════════════════
    //  INTERNAL — Build LP
    // ═════════════════════════════════════════════════════════

    function _buildLP(uint256 usdcAmount) internal returns (uint256 lpReceived) {
        uint256 fundBefore = IERC20(FUND).balanceOf(address(this));
        charityFund.deposit(usdcAmount);
        uint256 fundMinted = IERC20(FUND).balanceOf(address(this)) - fundBefore;
        uint256 halfFund = fundMinted / 2;

        // FUND -> TOKEN (FOT-safe): use the TOKEN actually received, not the quote.
        uint256 tokenForLP = _swapFundToToken(halfFund);

        uint256 fundForLP = fundMinted - halfFund;
        (,, lpReceived) = v2Router.addLiquidity(
            FUND, TOKEN, fundForLP, tokenForLP, 0, 0, address(this), block.timestamp
        );
        require(lpReceived > 0, "no LP");
    }

    // ═════════════════════════════════════════════════════════
    //  INTERNAL — Withdraw
    // ═════════════════════════════════════════════════════════

    function _doWithdraw(address user, uint256 shareAmount, bool asToken) internal {
        require(shareAmount > 0 && shareAmount <= shares[user], "bad shares");

        uint256 lpBal = IERC20(LP).balanceOf(address(this));
        uint256 lpToRemove = (lpBal * shareAmount) / totalShares;

        shares[user] -= shareAmount;
        totalShares -= shareAmount;

        // removeLiquidity sends TOKEN to this vault post-tax — measure the real TOKEN delta,
        // because the router's reported amountToken is the pre-tax amount the pair released.
        uint256 tokenBefore = IERC20(TOKEN).balanceOf(address(this));
        IERC20(LP).approve(address(v2Router), lpToRemove);
        (uint256 amtFund,) = v2Router.removeLiquidity(
            FUND, TOKEN, lpToRemove, 0, 0, address(this), block.timestamp
        );
        uint256 amtToken = IERC20(TOKEN).balanceOf(address(this)) - tokenBefore;

        if (asToken) {
            // Convert the FUND leg to TOKEN too, then pay out the full TOKEN the vault holds.
            // The unavoidable transfer tax on this final hop is borne by the recipient (true of
            // every transfer of a taxed token); the call cannot revert since we send exactly
            // what we hold.
            uint256 tokenOut = amtToken;
            if (amtFund > 0) {
                tokenOut += _swapFundToToken(amtFund);
            }
            if (tokenOut > 0) _safeTransfer(TOKEN, user, tokenOut);
            emit Withdrawn(user, shareAmount, tokenOut, true);
        } else {
            // Convert the TOKEN leg to FUND. Swap input is the real TOKEN we hold; output FUND
            // (untaxed) is measured by delta for safety. Then redeem FUND -> USDC by delta.
            uint256 fundToRedeem = amtFund;
            if (amtToken > 0) {
                fundToRedeem += _swapTokenToFund(amtToken);
            }
            uint256 usdcBefore = IERC20(USDC).balanceOf(address(this));
            if (fundToRedeem > 0) charityFund.redeem(fundToRedeem);
            uint256 usdcOut = IERC20(USDC).balanceOf(address(this)) - usdcBefore;
            if (usdcOut > 0) _safeTransfer(USDC, user, usdcOut);
            emit Withdrawn(user, shareAmount, usdcOut, false);
        }
    }

    // ═════════════════════════════════════════════════════════
    //  INTERNAL — FOT-safe swaps (return ACTUAL received, by balance delta)
    // ═════════════════════════════════════════════════════════

    /// @dev Swap `fundIn` FUND -> TOKEN with the fee-on-transfer-safe router call.
    ///      Returns the TOKEN actually received by this vault (post-tax).
    function _swapFundToToken(uint256 fundIn) internal returns (uint256 received) {
        require(fundIn > 0, "amount too small");
        _checkImpact(fundIn, true);
        address[] memory path = new address[](2);
        path[0] = FUND;
        path[1] = TOKEN;
        uint256 before = IERC20(TOKEN).balanceOf(address(this));
        v2Router.swapExactTokensForTokensSupportingFeeOnTransferTokens(
            fundIn, _minOutput(fundIn, true), path, address(this), block.timestamp
        );
        received = IERC20(TOKEN).balanceOf(address(this)) - before;
        require(received > 0, "no token out");
    }

    /// @dev Swap `tokenIn` TOKEN -> FUND with the fee-on-transfer-safe router call.
    ///      Returns the FUND actually received (FUND is untaxed; delta used for safety).
    function _swapTokenToFund(uint256 tokenIn) internal returns (uint256 received) {
        require(tokenIn > 0, "amount too small");
        _checkImpact(tokenIn, false);
        address[] memory path = new address[](2);
        path[0] = TOKEN;
        path[1] = FUND;
        uint256 before = IERC20(FUND).balanceOf(address(this));
        v2Router.swapExactTokensForTokensSupportingFeeOnTransferTokens(
            tokenIn, _minOutput(tokenIn, false), path, address(this), block.timestamp
        );
        received = IERC20(FUND).balanceOf(address(this)) - before;
        require(received > 0, "no fund out");
    }

    // ═════════════════════════════════════════════════════════
    //  INTERNAL — Slippage protection
    // ═════════════════════════════════════════════════════════

    function _checkImpact(uint256 swapAmount, bool fundToToken) internal view {
        (uint112 r0, uint112 r1,) = IUniswapV2Pair(LP).getReserves();
        uint256 reserveIn = fundToToken
            ? (fundIsToken0 ? uint256(r0) : uint256(r1))
            : (fundIsToken0 ? uint256(r1) : uint256(r0));
        require(reserveIn > 0, "pool empty");
        require(
            swapAmount * 10000 <= maxImpactBps * (reserveIn + swapAmount),
            "price impact too high"
        );
    }

    /// @dev Pre-tax constant-product expectation, discounted by maxImpactBps. For a taxed TOKEN
    ///      the realized output arrives below this pre-tax expectation, so maxImpactBps must be
    ///      set >= the token's transfer tax + real slippage or the FOT swap's own min-out check
    ///      will revert. This is the same single knob the clean vault uses; we intentionally do
    ///      NOT hardcode a tax rate here (taxes vary and can change). The on-the-token side, the
    ///      received amount is then re-measured by balance delta, so accounting stays exact.
    function _minOutput(uint256 swapAmount, bool fundToToken) internal view returns (uint256) {
        (uint112 r0, uint112 r1,) = IUniswapV2Pair(LP).getReserves();
        uint256 rIn; uint256 rOut;
        if (fundToToken) {
            rIn  = fundIsToken0 ? uint256(r0) : uint256(r1);
            rOut = fundIsToken0 ? uint256(r1) : uint256(r0);
        } else {
            rIn  = fundIsToken0 ? uint256(r1) : uint256(r0);
            rOut = fundIsToken0 ? uint256(r0) : uint256(r1);
        }
        uint256 aFee = swapAmount * 997;
        uint256 expected = (aFee * rOut) / (rIn * 1000 + aFee);
        return expected * (10000 - maxImpactBps) / 10000;
    }

    // ═════════════════════════════════════════════════════════
    //  INTERNAL — Token helpers
    // ═════════════════════════════════════════════════════════

    function _returnOperationDust(address to, uint256 fundBefore, uint256 tokenBefore) internal {
        uint256 fundNow = IERC20(FUND).balanceOf(address(this));
        uint256 tokenNow = IERC20(TOKEN).balanceOf(address(this));
        if (fundNow > fundBefore) _safeTransfer(FUND, to, fundNow - fundBefore);
        if (tokenNow > tokenBefore) _safeTransfer(TOKEN, to, tokenNow - tokenBefore);
    }

    function _safeTransfer(address token, address to, uint256 amt) internal {
        (bool ok, bytes memory data) = token.call(
            abi.encodeWithSelector(IERC20.transfer.selector, to, amt)
        );
        require(ok && (data.length == 0 || abi.decode(data, (bool))), "transfer failed");
    }

    function _safeTransferFrom(address token, address from, address to, uint256 amt) internal {
        (bool ok, bytes memory data) = token.call(
            abi.encodeWithSelector(IERC20.transferFrom.selector, from, to, amt)
        );
        require(ok && (data.length == 0 || abi.decode(data, (bool))), "transferFrom failed");
    }

    // ═════════════════════════════════════════════════════════
    //  VIEWS
    // ═════════════════════════════════════════════════════════

    function getInfo(address user) external view returns (
        uint256 userShares,
        uint256 userPending,
        uint256 userLP,
        uint256 vaultLP
    ) {
        userShares = shares[user];
        userPending = pendingDeposit[user];
        vaultLP = IERC20(LP).balanceOf(address(this));
        if (totalShares > 0) {
            userLP = (vaultLP * userShares) / totalShares;
        }
    }

    function compoundable() external view returns (uint256) {
        return IERC20(FUND).balanceOf(address(this));
    }

    function maxInstantDeposit() external view returns (uint256) {
        (uint112 r0, uint112 r1,) = IUniswapV2Pair(LP).getReserves();
        uint256 reserveFund = fundIsToken0 ? uint256(r0) : uint256(r1);
        if (reserveFund == 0) return 0;
        uint256 maxHalf = (maxImpactBps * reserveFund) / (10000 - maxImpactBps);
        return maxHalf * 2;
    }
}

