// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/// @title CommunityV3PoolVault — Slippage-protected community LP using Uniswap V3 full-range
/// @notice USDC -> CharityFund receipt -> swap half to TOKEN -> V3 full-range position.
///         Same user-facing interface as CommunityLPVaultV3 (V2 version).
///         compound() claims charity yield and deepens the position for all holders.

interface IERC20 {
    function approve(address, uint256) external returns (bool);
    function balanceOf(address) external view returns (uint256);
    function transfer(address, uint256) external returns (bool);
    function transferFrom(address, address, uint256) external returns (bool);
}

interface ICharityFund {
    function deposit(uint256) external;
    function redeem(uint256) external;
    function claimV3Position(uint256 tokenId) external;
    function registerV3Position(uint256 tokenId) external;
}

interface INonfungiblePositionManager {
    struct MintParams {
        address token0;
        address token1;
        uint24 fee;
        int24 tickLower;
        int24 tickUpper;
        uint256 amount0Desired;
        uint256 amount1Desired;
        uint256 amount0Min;
        uint256 amount1Min;
        address recipient;
        uint256 deadline;
    }
    struct IncreaseLiquidityParams {
        uint256 tokenId;
        uint256 amount0Desired;
        uint256 amount1Desired;
        uint256 amount0Min;
        uint256 amount1Min;
        uint256 deadline;
    }
    struct DecreaseLiquidityParams {
        uint256 tokenId;
        uint128 amount;
        uint256 amount0Min;
        uint256 amount1Min;
        uint256 deadline;
    }
    struct CollectParams {
        uint256 tokenId;
        address recipient;
        uint128 amount0Max;
        uint128 amount1Max;
    }
    function mint(MintParams calldata) external payable
        returns (uint256 tokenId, uint128 liquidity, uint256 amount0, uint256 amount1);
    function increaseLiquidity(IncreaseLiquidityParams calldata) external payable
        returns (uint128 liquidity, uint256 amount0, uint256 amount1);
    function decreaseLiquidity(DecreaseLiquidityParams calldata) external
        returns (uint256 amount0, uint256 amount1);
    function collect(CollectParams calldata) external payable
        returns (uint256 amount0, uint256 amount1);
    function positions(uint256) external view
        returns (uint96, address, address, address, uint24, int24, int24,
                 uint128 liquidity, uint256, uint256, uint128, uint128);
}

interface ISwapRouter {
    struct ExactInputSingleParams {
        address tokenIn;
        address tokenOut;
        uint24 fee;
        address recipient;
        uint256 amountIn;
        uint256 amountOutMinimum;
        uint160 sqrtPriceLimitX96;
    }
    function exactInputSingle(ExactInputSingleParams calldata) external payable
        returns (uint256 amountOut);
}

interface IUniswapV3Pool {
    function slot0() external view returns (
        uint160 sqrtPriceX96, int24 tick, uint16, uint16, uint16, uint8, bool);
    function liquidity() external view returns (uint128);
    function token0() external view returns (address);
    function fee() external view returns (uint24);
    function tickSpacing() external view returns (int24);
}

contract CommunityV3PoolVault {

    // ── Immutables ──────────────────────────────────────────
    address public immutable USDC;
    address public immutable FUND;
    address public immutable TOKEN;
    ICharityFund public immutable charityFund;
    INonfungiblePositionManager public immutable positionManager;
    ISwapRouter public immutable swapRouter;
    IUniswapV3Pool public immutable pool;
    uint24 public immutable poolFee;
    bool public immutable fundIsToken0;
    int24 public immutable tickLower;
    int24 public immutable tickUpper;
    address public immutable owner;

    // ── Config ──────────────────────────────────────────────
    uint256 public maxImpactBps;
    uint256 public constant MAX_IMPACT_CAP = 1500;

    // ── V3 Position ─────────────────────────────────────────
    uint256 public positionTokenId;

    // ── Shares ──────────────────────────────────────────────
    uint256 public totalShares;
    mapping(address => uint256) public shares;

    // ── Yield ─────────────────────────────────────────────
    bool public yieldRegistered;

    // ── Pending ─────────────────────────────────────────────
    mapping(address => uint256) public pendingDeposit;
    uint256 public totalPendingDeposit;

    // ── Reentrancy ──────────────────────────────────────────
    uint256 private _locked = 1;
    modifier nonReentrant() {
        require(_locked == 1, "reentrant");
        _locked = 2;
        _;
        _locked = 1;
    }

    // ── Events ──────────────────────────────────────────────
    event Deposited(address indexed user, uint256 shares, uint256 usdcIn);
    event DepositQueued(address indexed user, uint256 usdcAmount);
    event DepositCancelled(address indexed user, uint256 usdcAmount);
    event Withdrawn(address indexed user, uint256 shares, uint256 amountOut, bool asToken);
    event Compounded(address indexed caller, uint256 fundUsed, uint128 liquidityAdded);
    event Donated(address indexed donor, uint256 usdcAmount, uint256 liquidityAdded);
    event MaxImpactChanged(uint256 oldBps, uint256 newBps);

    // ═════════════════════════════════════════════════════════
    //  Constructor
    // ═════════════════════════════════════════════════════════

    constructor(
        address _usdc,
        address _fund,
        address _token,
        address _pool,
        address _positionManager,
        address _swapRouter,
        uint256 _maxImpactBps
    ) {
        require(_maxImpactBps > 0 && _maxImpactBps <= MAX_IMPACT_CAP, "invalid impact");
        USDC  = _usdc;
        FUND  = _fund;
        TOKEN = _token;
        charityFund     = ICharityFund(_fund);
        positionManager = INonfungiblePositionManager(_positionManager);
        swapRouter      = ISwapRouter(_swapRouter);
        pool            = IUniswapV3Pool(_pool);
        maxImpactBps    = _maxImpactBps;
        owner           = msg.sender;

        poolFee = IUniswapV3Pool(_pool).fee();
        int24 ts = IUniswapV3Pool(_pool).tickSpacing();
        tickLower = (-887272 / ts) * ts;
        tickUpper = (887272 / ts) * ts;
        fundIsToken0 = IUniswapV3Pool(_pool).token0() == _fund;

        IERC20(_usdc).approve(_fund, type(uint256).max);
        IERC20(_fund).approve(_swapRouter, type(uint256).max);
        IERC20(_token).approve(_swapRouter, type(uint256).max);
        IERC20(_fund).approve(_positionManager, type(uint256).max);
        IERC20(_token).approve(_positionManager, type(uint256).max);
    }

    /// @dev Accept NFT from position manager
    function onERC721Received(address, address, uint256, bytes calldata)
        external pure returns (bytes4)
    {
        return this.onERC721Received.selector;
    }

    // ═════════════════════════════════════════════════════════
    //  Config
    // ═════════════════════════════════════════════════════════

    function setMaxImpact(uint256 bps) external {
        require(msg.sender == owner, "not owner");
        require(bps > 0 && bps <= MAX_IMPACT_CAP, "invalid");
        emit MaxImpactChanged(maxImpactBps, bps);
        maxImpactBps = bps;
    }

    // ═════════════════════════════════════════════════════════
    //  COMPOUND — claim charity yield, deepen position for all holders
    // ═════════════════════════════════════════════════════════

    /// @notice Register the vault's V3 position with CharityFund for yield. Anyone can call once.
    function registerForYield() external {
        require(positionTokenId != 0, "no position");
        require(!yieldRegistered, "already registered");
        charityFund.registerV3Position(positionTokenId);
        yieldRegistered = true;
    }

    /// @notice Claim charity yield and deepen the V3 position. Anyone can call.
    ///         Grows total liquidity without changing shares — all holders benefit proportionally.
    function compound() external nonReentrant {
        require(totalShares > 0, "no depositors");
        require(positionTokenId != 0, "no position");

        // 1. Claim yield from CharityFund (sends FUND tokens to this vault)
        if (yieldRegistered) {
            try charityFund.claimV3Position(positionTokenId) {} catch {}
        }

        // 2. Collect trading fees from the position
        positionManager.collect(
            INonfungiblePositionManager.CollectParams({
                tokenId:    positionTokenId,
                recipient:  address(this),
                amount0Max: type(uint128).max,
                amount1Max: type(uint128).max
            })
        );

        // 3. Use all available FUND (yield + fees + dust)
        uint256 fundBal = IERC20(FUND).balanceOf(address(this));
        uint256 tokenBal = IERC20(TOKEN).balanceOf(address(this));

        // If we have TOKEN from fees, swap to FUND first so everything goes through one path
        if (tokenBal > 0) {
            _checkImpact(tokenBal, false);
            fundBal += swapRouter.exactInputSingle(
                ISwapRouter.ExactInputSingleParams({
                    tokenIn: TOKEN, tokenOut: FUND, fee: poolFee,
                    recipient: address(this), amountIn: tokenBal,
                    amountOutMinimum: _minOutput(tokenBal, false),
                    sqrtPriceLimitX96: 0
                })
            );
            fundBal = IERC20(FUND).balanceOf(address(this));
        }

        require(fundBal > 0, "nothing to compound");
        uint256 halfFund = fundBal / 2;
        require(halfFund > 0, "amount too small");

        // 4. Swap half FUND -> TOKEN (slippage-protected)
        _checkImpact(halfFund, true);
        uint256 tokenReceived = swapRouter.exactInputSingle(
            ISwapRouter.ExactInputSingleParams({
                tokenIn: FUND, tokenOut: TOKEN, fee: poolFee,
                recipient: address(this), amountIn: halfFund,
                amountOutMinimum: _minOutput(halfFund, true),
                sqrtPriceLimitX96: 0
            })
        );

        // 5. Deepen the V3 position
        uint256 fundForLP = fundBal - halfFund;
        (uint256 a0, uint256 a1) = fundIsToken0
            ? (fundForLP, tokenReceived)
            : (tokenReceived, fundForLP);

        (uint128 liqAdded,,) = positionManager.increaseLiquidity(
            INonfungiblePositionManager.IncreaseLiquidityParams({
                tokenId: positionTokenId,
                amount0Desired: a0,
                amount1Desired: a1,
                amount0Min: 0,
                amount1Min: 0,
                deadline: block.timestamp
            })
        );

        emit Compounded(msg.sender, fundBal, liqAdded);
    }

    /// @notice Donate USDC as a prize — deepens position for all holders, no shares minted.
    function donate(uint256 usdcAmount) external nonReentrant {
        require(usdcAmount > 0, "zero");
        require(totalShares > 0, "no depositors");
        _safeTransferFrom(USDC, msg.sender, address(this), usdcAmount);

        uint256 liq = _buildLP(usdcAmount);
        // No shares minted — liquidity grows but totalShares stays the same
        // Every holder's proportional value increases
        emit Donated(msg.sender, usdcAmount, liq);
    }

    // ═════════════════════════════════════════════════════════
    //  INSTANT DEPOSIT
    // ═════════════════════════════════════════════════════════

    function deposit(uint256 usdcAmount) external nonReentrant {
        require(usdcAmount > 0, "zero");
        _safeTransferFrom(USDC, msg.sender, address(this), usdcAmount);

        uint256 fundBefore  = IERC20(FUND).balanceOf(address(this));
        uint256 tokenBefore = IERC20(TOKEN).balanceOf(address(this));

        uint256 liq = _buildLP(usdcAmount);
        shares[msg.sender] += liq;
        totalShares += liq;

        _returnOperationDust(msg.sender, fundBefore, tokenBefore);
        emit Deposited(msg.sender, liq, usdcAmount);
    }

    // ═════════════════════════════════════════════════════════
    //  QUEUED DEPOSIT
    // ═════════════════════════════════════════════════════════

    function depositQueued(uint256 usdcAmount) external nonReentrant {
        require(usdcAmount > 0, "zero");
        _safeTransferFrom(USDC, msg.sender, address(this), usdcAmount);
        pendingDeposit[msg.sender] += usdcAmount;
        totalPendingDeposit += usdcAmount;
        emit DepositQueued(msg.sender, usdcAmount);
    }

    function processDeposit(address user, uint256 usdcAmount) external nonReentrant {
        require(usdcAmount > 0 && usdcAmount <= pendingDeposit[user], "bad amount");
        pendingDeposit[user] -= usdcAmount;
        totalPendingDeposit -= usdcAmount;

        uint256 fundBefore  = IERC20(FUND).balanceOf(address(this));
        uint256 tokenBefore = IERC20(TOKEN).balanceOf(address(this));

        uint256 liq = _buildLP(usdcAmount);
        shares[user] += liq;
        totalShares += liq;

        _returnOperationDust(user, fundBefore, tokenBefore);
        emit Deposited(user, liq, usdcAmount);
    }

    function cancelDeposit(uint256 usdcAmount) external nonReentrant {
        require(usdcAmount > 0 && usdcAmount <= pendingDeposit[msg.sender], "bad amount");
        pendingDeposit[msg.sender] -= usdcAmount;
        totalPendingDeposit -= usdcAmount;
        _safeTransfer(USDC, msg.sender, usdcAmount);
        emit DepositCancelled(msg.sender, usdcAmount);
    }

    // ═════════════════════════════════════════════════════════
    //  WITHDRAW
    // ═════════════════════════════════════════════════════════

    function withdraw(uint256 shareAmount) external nonReentrant {
        _doWithdraw(msg.sender, shareAmount, false);
    }

    function withdrawAsToken(uint256 shareAmount) external nonReentrant {
        _doWithdraw(msg.sender, shareAmount, true);
    }

    // ═════════════════════════════════════════════════════════
    //  INTERNAL — Build LP (V3 full-range)
    // ═════════════════════════════════════════════════════════

    function _buildLP(uint256 usdcAmount) internal returns (uint256 liquidityAdded) {
        // Step 1: USDC → FUND
        uint256 fundBefore = IERC20(FUND).balanceOf(address(this));
        charityFund.deposit(usdcAmount);
        uint256 fundMinted = IERC20(FUND).balanceOf(address(this)) - fundBefore;
        uint256 halfFund = fundMinted / 2;

        // Step 2: Swap half FUND → TOKEN via V3
        _checkImpact(halfFund, true);
        uint256 tokenReceived = swapRouter.exactInputSingle(
            ISwapRouter.ExactInputSingleParams({
                tokenIn:  FUND,
                tokenOut: TOKEN,
                fee:      poolFee,
                recipient: address(this),
                amountIn: halfFund,
                amountOutMinimum: _minOutput(halfFund, true),
                sqrtPriceLimitX96: 0
            })
        );

        // Step 3: Add V3 full-range liquidity
        uint256 fundForLP  = fundMinted - halfFund;
        (uint256 a0, uint256 a1) = fundIsToken0
            ? (fundForLP, tokenReceived)
            : (tokenReceived, fundForLP);

        if (positionTokenId == 0) {
            (uint256 tokenId, uint128 liq,,) = positionManager.mint(
                INonfungiblePositionManager.MintParams({
                    token0:  fundIsToken0 ? FUND : TOKEN,
                    token1:  fundIsToken0 ? TOKEN : FUND,
                    fee:     poolFee,
                    tickLower: tickLower,
                    tickUpper: tickUpper,
                    amount0Desired: a0,
                    amount1Desired: a1,
                    amount0Min: 0,
                    amount1Min: 0,
                    recipient: address(this),
                    deadline: block.timestamp
                })
            );
            require(liq > 0, "no liquidity");
            positionTokenId = tokenId;
            liquidityAdded = uint256(liq);
        } else {
            (uint128 liq,,) = positionManager.increaseLiquidity(
                INonfungiblePositionManager.IncreaseLiquidityParams({
                    tokenId: positionTokenId,
                    amount0Desired: a0,
                    amount1Desired: a1,
                    amount0Min: 0,
                    amount1Min: 0,
                    deadline: block.timestamp
                })
            );
            require(liq > 0, "no liquidity");
            liquidityAdded = uint256(liq);
        }
    }

    // ═════════════════════════════════════════════════════════
    //  INTERNAL — Withdraw
    // ═════════════════════════════════════════════════════════

    function _doWithdraw(address user, uint256 shareAmount, bool asToken) internal {
        require(shareAmount > 0 && shareAmount <= shares[user], "bad shares");
        require(positionTokenId != 0, "no position");

        (,,,,,,, uint128 totalLiq,,,,) = positionManager.positions(positionTokenId);
        uint128 liqToRemove = uint128((uint256(totalLiq) * shareAmount) / totalShares);

        shares[user] -= shareAmount;
        totalShares  -= shareAmount;

        // Remove liquidity (principal only)
        (uint256 amt0, uint256 amt1) = positionManager.decreaseLiquidity(
            INonfungiblePositionManager.DecreaseLiquidityParams({
                tokenId: positionTokenId,
                amount:  liqToRemove,
                amount0Min: 0,
                amount1Min: 0,
                deadline: block.timestamp
            })
        );

        // Collect the removed tokens (fees stay in position for remaining holders)
        positionManager.collect(
            INonfungiblePositionManager.CollectParams({
                tokenId:    positionTokenId,
                recipient:  address(this),
                amount0Max: uint128(amt0),
                amount1Max: uint128(amt1)
            })
        );

        uint256 amtFund  = fundIsToken0 ? amt0 : amt1;
        uint256 amtToken = fundIsToken0 ? amt1 : amt0;

        if (asToken) {
            uint256 tokenOut = amtToken;
            if (amtFund > 0) {
                _checkImpact(amtFund, true);
                tokenOut += swapRouter.exactInputSingle(
                    ISwapRouter.ExactInputSingleParams({
                        tokenIn: FUND, tokenOut: TOKEN, fee: poolFee,
                        recipient: address(this), amountIn: amtFund,
                        amountOutMinimum: _minOutput(amtFund, true),
                        sqrtPriceLimitX96: 0
                    })
                );
            }
            if (tokenOut > 0) _safeTransfer(TOKEN, user, tokenOut);
            emit Withdrawn(user, shareAmount, tokenOut, true);
        } else {
            uint256 fundToRedeem = amtFund;
            if (amtToken > 0) {
                _checkImpact(amtToken, false);
                fundToRedeem += swapRouter.exactInputSingle(
                    ISwapRouter.ExactInputSingleParams({
                        tokenIn: TOKEN, tokenOut: FUND, fee: poolFee,
                        recipient: address(this), amountIn: amtToken,
                        amountOutMinimum: _minOutput(amtToken, false),
                        sqrtPriceLimitX96: 0
                    })
                );
            }
            uint256 usdcBefore = IERC20(USDC).balanceOf(address(this));
            if (fundToRedeem > 0) charityFund.redeem(fundToRedeem);
            uint256 usdcOut = IERC20(USDC).balanceOf(address(this)) - usdcBefore;
            if (usdcOut > 0) _safeTransfer(USDC, user, usdcOut);
            emit Withdrawn(user, shareAmount, usdcOut, false);
        }
    }

    // ═════════════════════════════════════════════════════════
    //  INTERNAL — Slippage protection (V3 liquidity-based)
    // ═════════════════════════════════════════════════════════

    function _checkImpact(uint256 swapAmount, bool fundToToken) internal view {
        uint128 L = pool.liquidity();
        (uint160 sqrtPriceX96,,,,,,) = pool.slot0();
        require(L > 0, "pool empty");

        bool sellingToken0 = fundToToken ? fundIsToken0 : !fundIsToken0;
        uint256 reserveIn;
        if (sellingToken0) {
            reserveIn = (uint256(L) << 96) / uint256(sqrtPriceX96);
        } else {
            reserveIn = (uint256(L) * uint256(sqrtPriceX96)) >> 96;
        }
        require(reserveIn > 0, "no liquidity");
        require(
            swapAmount * 10000 <= maxImpactBps * (reserveIn + swapAmount),
            "price impact too high"
        );
    }

    function _minOutput(uint256 swapAmount, bool fundToToken) internal view returns (uint256) {
        (uint160 sqrtPriceX96,,,,,,) = pool.slot0();
        uint256 S = uint256(sqrtPriceX96);
        bool sellingToken0 = fundToToken ? fundIsToken0 : !fundIsToken0;

        uint256 expected;
        if (sellingToken0) {
            expected = swapAmount * S / (1 << 96) * S / (1 << 96);
        } else {
            expected = (swapAmount << 96) / S * (1 << 96) / S;
        }
        expected = expected * (1e6 - uint256(poolFee)) / 1e6;
        return expected * (10000 - maxImpactBps) / 10000;
    }

    // ═════════════════════════════════════════════════════════
    //  INTERNAL — Token helpers
    // ═════════════════════════════════════════════════════════

    function _returnOperationDust(address to, uint256 fundBefore, uint256 tokenBefore) internal {
        uint256 fundNow  = IERC20(FUND).balanceOf(address(this));
        uint256 tokenNow = IERC20(TOKEN).balanceOf(address(this));
        if (fundNow > fundBefore)  _safeTransfer(FUND, to, fundNow - fundBefore);
        if (tokenNow > tokenBefore) _safeTransfer(TOKEN, to, tokenNow - tokenBefore);
    }

    function _safeTransfer(address token, address to, uint256 amt) internal {
        (bool ok, bytes memory data) = token.call(
            abi.encodeWithSelector(IERC20.transfer.selector, to, amt)
        );
        require(ok && (data.length == 0 || abi.decode(data, (bool))), "transfer failed");
    }

    function _safeTransferFrom(address token, address from, address to, uint256 amt) internal {
        (bool ok, bytes memory data) = token.call(
            abi.encodeWithSelector(IERC20.transferFrom.selector, from, to, amt)
        );
        require(ok && (data.length == 0 || abi.decode(data, (bool))), "transferFrom failed");
    }

    // ═════════════════════════════════════════════════════════
    //  VIEWS
    // ═════════════════════════════════════════════════════════

    function getInfo(address user) external view returns (
        uint256 userShares,
        uint256 userPending,
        uint256 userLiquidity,
        uint256 totalLiquidity
    ) {
        userShares  = shares[user];
        userPending = pendingDeposit[user];
        if (positionTokenId != 0) {
            (,,,,,,, uint128 liq,,,,) = positionManager.positions(positionTokenId);
            totalLiquidity = uint256(liq);
            if (totalShares > 0) {
                userLiquidity = (totalLiquidity * userShares) / totalShares;
            }
        }
    }

    /// @notice FUND tokens sitting in the vault available to compound
    function compoundable() external view returns (uint256) {
        return IERC20(FUND).balanceOf(address(this));
    }

    function maxInstantDeposit() external view returns (uint256) {
        uint128 L = pool.liquidity();
        (uint160 sqrtPriceX96,,,,,,) = pool.slot0();
        if (L == 0) return 0;

        uint256 reserveFund;
        if (fundIsToken0) {
            reserveFund = (uint256(L) << 96) / uint256(sqrtPriceX96);
        } else {
            reserveFund = (uint256(L) * uint256(sqrtPriceX96)) >> 96;
        }
        if (reserveFund == 0) return 0;
        uint256 maxHalf = (maxImpactBps * reserveFund) / (10000 - maxImpactBps);
        return maxHalf * 2;
    }
}

