// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/// @title MfTVaultFactoryFOT — Fee-on-transfer (taxed-token) variant of MfTVaultFactory
/// @notice IDENTICAL to MfTVaultFactory (same constants, same one-tx flow: pull token + USDC →
///         mint Money → seed Money/Token V2 LP → burn seed LP to dead → deploy a vault clone)
///         with ONE class of fix: the community TOKEN may charge a transfer tax (e.g. Midas ~2%).
///         USDC and the Money (FUND) token are standard ERC20s and are NOT taxed; only TOKEN is.
///
///         The clean factory pulls `tokenAmount` via transferFrom but a taxed token delivers
///         LESS, then calls addLiquidity with the FULL `tokenAmount`, so the router's
///         safeTransferFrom tries to pull more TOKEN than the factory holds and reverts with
///         "TransferHelper: TRANSFER_FROM_FAILED". This variant measures the TOKEN actually
///         received (balanceOf delta) and seeds liquidity with that real amount, so the router
///         only ever pulls what is truly held.
///
///         Deploy this factory pointing at the CommunityLPVaultFOTInit implementation (the
///         FOT-safe vault clone), so deposits/withdraws are also tax-safe.

interface IERC20 {
    function approve(address, uint256) external returns (bool);
    function balanceOf(address) external view returns (uint256);
    function transfer(address, uint256) external returns (bool);
    function transferFrom(address, address, uint256) external returns (bool);
    function symbol() external view returns (string memory);
    function decimals() external view returns (uint8);
}

interface ICharityFund {
    function deposit(uint256) external;
}

interface IUniswapV2Factory {
    function createPair(address, address) external returns (address);
    function getPair(address, address) external view returns (address);
}

interface IUniswapV2Router02 {
    function addLiquidity(
        address, address, uint256, uint256, uint256, uint256, address, uint256
    ) external returns (uint256, uint256, uint256);
}

interface ICommunityLPVaultV3Init {
    function initialize(
        address usdc, address fund, address token, address lp,
        address v2Router, uint256 maxImpactBps, address owner
    ) external;
}

contract MfTVaultFactoryFOT {

    // ── Constants ─────────────────────────────────────────────
    address public constant USDC = 0x833589fCD6eDb6E08f4c7C32D4f71b54bdA02913;
    address public constant FUND = 0xe3dd3881477c20C17Df080cEec0C1bD0C065A072;
    address public constant DEAD = 0x000000000000000000000000000000000000dEaD;
    uint256 public constant MIN_USDC = 10_000_000; // $10 (6 decimals)

    // ── Immutables ────────────────────────────────────────────
    IUniswapV2Factory public immutable v2Factory;
    IUniswapV2Router02 public immutable v2Router;
    ICharityFund public immutable charityFund;
    address public immutable implementation;

    // ── Registry ──────────────────────────────────────────────
    address[] public vaults;
    mapping(address => address[]) public vaultsByToken;

    // ── Events ────────────────────────────────────────────────
    event VaultCreated(
        address indexed vault,
        address indexed token,
        address indexed creator,
        address lp,
        uint256 seedUsdc,
        uint256 seedToken,
        uint256 seedLpBurned
    );

    // ── Constructor ───────────────────────────────────────────
    constructor(address _v2Factory, address _v2Router, address _implementation) {
        v2Factory     = IUniswapV2Factory(_v2Factory);
        v2Router      = IUniswapV2Router02(_v2Router);
        charityFund   = ICharityFund(FUND);
        implementation = _implementation;
    }

    // ═════════════════════════════════════════════════════════
    //  CREATE VAULT
    // ═════════════════════════════════════════════════════════

    /// @notice Create a community vault in one transaction (taxed-token safe)
    /// @param token       The meme/community token address (may charge a transfer tax)
    /// @param usdcAmount  USDC to seed (min $10, 6 decimals)
    /// @param tokenAmount Token amount to PULL from creator (sets initial price; the amount
    ///                    actually seeded is what arrives post-tax)
    /// @param maxImpactBps Max price impact for vault swaps (1-1500). For a taxed token set this
    ///                    >= the token's transfer tax + slippage headroom.
    /// @return vault      The deployed vault clone address
    function createVault(
        address token,
        uint256 usdcAmount,
        uint256 tokenAmount,
        uint256 maxImpactBps
    ) external returns (address vault) {
        require(usdcAmount >= MIN_USDC, "min $10 USDC");
        require(tokenAmount > 0, "need token");
        require(token != USDC && token != FUND && token != DEAD, "invalid token");
        require(maxImpactBps > 0 && maxImpactBps <= 1500, "impact 1-1500");

        // 1. Pull USDC + token from creator. The token is taxed, so measure what actually
        //    arrived (balanceOf delta) rather than trusting the requested amount.
        _safeTransferFrom(USDC, msg.sender, address(this), usdcAmount);
        uint256 tokenBefore = IERC20(token).balanceOf(address(this));
        _safeTransferFrom(token, msg.sender, address(this), tokenAmount);
        uint256 tokenReceived = IERC20(token).balanceOf(address(this)) - tokenBefore;
        require(tokenReceived > 0, "no token received");

        // 2. Mint MfT Money from USDC
        IERC20(USDC).approve(FUND, usdcAmount);
        uint256 fundBefore = IERC20(FUND).balanceOf(address(this));
        charityFund.deposit(usdcAmount);
        uint256 fundMinted = IERC20(FUND).balanceOf(address(this)) - fundBefore;
        require(fundMinted > 0, "no Money minted");

        // 3. Get or create V2 pair (Money/Token)
        address lp = v2Factory.getPair(FUND, token);
        if (lp == address(0)) {
            lp = v2Factory.createPair(FUND, token);
        }

        // 4. Add seed liquidity using the TOKEN actually held (not the requested amount), so
        //    the router's transferFrom never tries to pull more than the factory owns.
        IERC20(FUND).approve(address(v2Router), fundMinted);
        IERC20(token).approve(address(v2Router), tokenReceived);
        (,, uint256 lpReceived) = v2Router.addLiquidity(
            FUND, token, fundMinted, tokenReceived,
            0, 0, address(this), block.timestamp
        );
        require(lpReceived > 0, "no LP minted");

        // 5. Burn seed LP forever (send to 0xdead)
        _safeTransfer(lp, DEAD, lpReceived);

        // 6. Deploy clone
        vault = _clone(implementation);
        ICommunityLPVaultV3Init(vault).initialize(
            USDC, FUND, token, lp, address(v2Router), maxImpactBps, msg.sender
        );

        // 7. Register
        vaults.push(vault);
        vaultsByToken[token].push(vault);

        // 8. Return any dust to creator
        uint256 fundDust = IERC20(FUND).balanceOf(address(this));
        uint256 tokenDust = IERC20(token).balanceOf(address(this));
        if (fundDust > 0) _safeTransfer(FUND, msg.sender, fundDust);
        if (tokenDust > 0) _safeTransfer(token, msg.sender, tokenDust);

        emit VaultCreated(vault, token, msg.sender, lp, usdcAmount, tokenReceived, lpReceived);
    }

    // ═════════════════════════════════════════════════════════
    //  VIEWS
    // ═════════════════════════════════════════════════════════

    function vaultCount() external view returns (uint256) {
        return vaults.length;
    }

    function vaultsForToken(address token) external view returns (address[] memory) {
        return vaultsByToken[token];
    }

    // ═════════════════════════════════════════════════════════
    //  INTERNAL — EIP-1167 Clone
    // ═════════════════════════════════════════════════════════

    function _clone(address impl) internal returns (address instance) {
        /// @solidity memory-safe-assembly
        assembly {
            let ptr := mload(0x40)
            mstore(ptr, 0x3d602d80600a3d3981f3363d3d373d3d3d363d73000000000000000000000000)
            mstore(add(ptr, 0x14), shl(0x60, impl))
            mstore(add(ptr, 0x28), 0x5af43d82803e903d91602b57fd5bf30000000000000000000000000000000000)
            instance := create(0, ptr, 0x37)
        }
        require(instance != address(0), "clone failed");
    }

    // ═════════════════════════════════════════════════════════
    //  INTERNAL — Safe transfers
    // ═════════════════════════════════════════════════════════

    function _safeTransfer(address tkn, address to, uint256 amt) internal {
        (bool ok, bytes memory data) = tkn.call(
            abi.encodeWithSelector(IERC20.transfer.selector, to, amt)
        );
        require(ok && (data.length == 0 || abi.decode(data, (bool))), "transfer failed");
    }

    function _safeTransferFrom(address tkn, address from, address to, uint256 amt) internal {
        (bool ok, bytes memory data) = tkn.call(
            abi.encodeWithSelector(IERC20.transferFrom.selector, from, to, amt)
        );
        require(ok && (data.length == 0 || abi.decode(data, (bool))), "transferFrom failed");
    }
}

