// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";

/// @title MockTaxToken — a faithful fee-on-transfer ERC20 for fork tests ONLY.
/// @notice Charges a flat `taxBps` on EVERY transfer/transferFrom (including the legs the
///         Uniswap router performs), burning the tax to the dead address — the same shape as
///         Midas-style taxed tokens. Used to prove MfTVaultFactoryFOT + CommunityLPVaultFOTInit
///         seed/deposit/withdraw without reverting and account by real balance deltas.
///         An optional allowlist can exempt addresses (e.g. the pair) from tax, to mirror real
///         tokens that exempt their own LP — the test exercises BOTH modes.
contract MockTaxToken is ERC20 {
    uint256 public immutable taxBps;          // e.g. 200 = 2%
    address public constant DEAD = 0x000000000000000000000000000000000000dEaD;
    address public immutable owner;
    mapping(address => bool) public taxExempt; // exempt from tax on send OR receive

    constructor(uint256 _taxBps) ERC20("Mock Tax Token", "MTAX") {
        require(_taxBps < 10000, "tax too high");
        taxBps = _taxBps;
        owner = msg.sender;
    }

    function mint(address to, uint256 amount) external {
        _mint(to, amount);
    }

    function setExempt(address a, bool v) external {
        require(msg.sender == owner, "not owner");
        taxExempt[a] = v;
    }

    /// @dev OZ v5 routes all moves through _update. We override it to skim the tax on transfers
    ///      while leaving mints/burns (from==0 or to==0) untaxed.
    function _update(address from, address to, uint256 value) internal override {
        if (from == address(0) || to == address(0) || taxBps == 0 ||
            taxExempt[from] || taxExempt[to]) {
            super._update(from, to, value);
            return;
        }
        uint256 tax = (value * taxBps) / 10000;
        if (tax > 0) {
            super._update(from, DEAD, tax);
        }
        super._update(from, to, value - tax);
    }
}

project/contracts/MoneyPegVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/// @title MoneyPegVault — USDC/Money tight-band LP, peg-supporting, charity-yield compounding
/// @notice Pool is USDC(token0)/Money(token1) on Uniswap V3. "Money" is a CharityFund receipt,
///         redeemable 1:1 for USDC. Deposit USDC -> concentrated liquidity in a tight band at ~$1.
///         NO SWAPS: the USDC<->Money conversion is 1:1 mint/redeem via the CharityFund, so deposits
///         have no price-impact/slippage risk. Range-aware split:
///           - below band  -> 100% USDC (token0)
///           - above band  -> 100% Money (token1)
///           - in band     -> proportional split
///         Withdraw always returns USDC. compound() folds trading fees + charity yield back in.
///         Adapted from the deployed TreePegVaultV2 pattern, minus the swap legs.

interface IERC20 {
    function approve(address spender, uint256 amount) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
    function transfer(address to, uint256 amount) external returns (bool);
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
}

/// @dev Money / CharityFund receipt: deposit(usdc) mints 1:1, redeem(money) returns 1:1 USDC.
interface ICharityFund {
    function deposit(uint256 amount) external;
    function redeem(uint256 amount) external;
    function registerV3Position(uint256 tokenId) external;
    function claimV3Position(uint256 tokenId) external;
}

interface INonfungiblePositionManager {
    struct MintParams {
        address token0; address token1; uint24 fee;
        int24 tickLower; int24 tickUpper;
        uint256 amount0Desired; uint256 amount1Desired;
        uint256 amount0Min; uint256 amount1Min;
        address recipient; uint256 deadline;
    }
    struct IncreaseLiquidityParams {
        uint256 tokenId;
        uint256 amount0Desired; uint256 amount1Desired;
        uint256 amount0Min; uint256 amount1Min;
        uint256 deadline;
    }
    struct DecreaseLiquidityParams {
        uint256 tokenId; uint128 liquidity;
        uint256 amount0Min; uint256 amount1Min;
        uint256 deadline;
    }
    struct CollectParams {
        uint256 tokenId; address recipient;
        uint128 amount0Max; uint128 amount1Max;
    }
    function mint(MintParams calldata) external payable returns (uint256, uint128, uint256, uint256);
    function increaseLiquidity(IncreaseLiquidityParams calldata) external payable returns (uint128, uint256, uint256);
    function decreaseLiquidity(DecreaseLiquidityParams calldata) external payable returns (uint256, uint256);
    function collect(CollectParams calldata) external payable returns (uint256, uint256);
    function positions(uint256) external view returns (
        uint96, address, address, address, uint24, int24, int24, uint128,
        uint256, uint256, uint128, uint128
    );
}

interface IUniswapV3Pool {
    function slot0() external view returns (
        uint160 sqrtPriceX96, int24 tick, uint16, uint16, uint16, uint8, bool
    );
}

contract MoneyPegVault {

    // ── Addresses (immutable) ─────────────────────────────────────────────
    address public immutable USDC;    // token0, 6 dec
    address public immutable MONEY;   // token1, 6 dec — CharityFund receipt (1:1 USDC)
    address public immutable pool;    // USDC/Money V3 pool
    INonfungiblePositionManager public immutable pm;

    uint24 public immutable poolFee;  // pool fee tier (e.g. 100 = 0.01%)
    int24  public immutable tickLower; // tight band lower bound
    int24  public immutable tickUpper; // tight band upper bound
    address public immutable owner;

    /// @dev Burn sink for permanently-locked seed shares — never withdrawable.
    address private constant DEAD = 0x000000000000000000000000000000000000dEaD;

    // ── State ─────────────────────────────────────────────────────────────
    uint256 public positionId;
    uint256 public totalShares;
    mapping(address => uint256) public shares;
    bool public yieldRegistered;

    // ── Reentrancy ────────────────────────────────────────────────────────
    uint256 private _locked = 1;
    modifier nonReentrant() {
        require(_locked == 1, "reentrant");
        _locked = 2;
        _;
        _locked = 1;
    }

    // ── Events ────────────────────────────────────────────────────────────
    event Deposited(address indexed user, uint256 shares, uint256 usdcIn);
    event Withdrawn(address indexed user, uint256 shares, uint256 usdcOut);
    event Compounded(address indexed caller, uint256 usdcFolded, uint256 moneyFolded);

    // ═════════════════════════════════════════════════════════════════════
    //  Constructor
    // ═════════════════════════════════════════════════════════════════════

    constructor(
        address _usdc,
        address _money,
        address _pool,
        address _pm,
        uint24  _poolFee,
        int24   _tickLower,
        int24   _tickUpper
    ) {
        require(_usdc < _money, "token order: usdc must be token0");
        require(_tickLower < _tickUpper, "bad band");
        USDC      = _usdc;
        MONEY     = _money;
        pool      = _pool;
        pm        = INonfungiblePositionManager(_pm);
        poolFee   = _poolFee;
        tickLower = _tickLower;
        tickUpper = _tickUpper;
        owner     = msg.sender;

        // One-time approvals
        IERC20(_usdc).approve(_pm, type(uint256).max);   // add liquidity
        IERC20(_money).approve(_pm, type(uint256).max);  // add liquidity
        IERC20(_usdc).approve(_money, type(uint256).max); // CharityFund.deposit pulls USDC
    }

    // ═════════════════════════════════════════════════════════════════════
    //  Deposit USDC — range-aware, no swaps
    // ═════════════════════════════════════════════════════════════════════

    /// @notice Deposit USDC and receive withdrawable shares.
    function deposit(uint256 usdcAmount) external nonReentrant {
        _doDeposit(msg.sender, usdcAmount);
    }

    /// @notice Seed permanent base liquidity. Shares are credited to a dead address and can
    ///         NEVER be withdrawn — the seed stays locked in the band forever (Unrugable base).
    ///         Identical mechanics to deposit(); only the share owner differs.
    function seed(uint256 usdcAmount) external nonReentrant {
        _doDeposit(DEAD, usdcAmount);
    }

    function _doDeposit(address creditTo, uint256 usdcAmount) internal {
        require(usdcAmount > 0, "zero");
        _safeTransferFrom(USDC, msg.sender, address(this), usdcAmount);

        uint256 usdcBefore  = IERC20(USDC).balanceOf(address(this)) - usdcAmount; // pre-existing dust baseline
        uint256 moneyBefore = IERC20(MONEY).balanceOf(address(this));

        uint256 moneyFrac    = _getToken1Fraction();         // bps that should be Money (token1)
        uint256 usdcForMoney = (usdcAmount * moneyFrac) / 10000;
        uint256 usdcForLP    = usdcAmount - usdcForMoney;
        uint256 moneyForLP   = 0;

        if (usdcForMoney > 0) {
            uint256 mBefore = IERC20(MONEY).balanceOf(address(this));
            ICharityFund(MONEY).deposit(usdcForMoney); // mint Money 1:1 from USDC
            moneyForLP = IERC20(MONEY).balanceOf(address(this)) - mBefore;
        }

        uint128 liq = _addLiquidity(usdcForLP, moneyForLP);
        require(liq > 0, "no liquidity");

        shares[creditTo] += uint256(liq);
        totalShares      += uint256(liq);

        // Return only dust this op created (unused USDC/Money from the add), never pre-existing balances
        _returnDust(msg.sender, usdcBefore, moneyBefore);
        emit Deposited(creditTo, uint256(liq), usdcAmount);
    }

    // ═════════════════════════════════════════════════════════════════════
    //  Withdraw — always returns USDC
    // ═════════════════════════════════════════════════════════════════════

    function withdraw(uint256 shareAmount) external nonReentrant {
        require(shareAmount > 0 && shareAmount <= shares[msg.sender], "bad shares");
        require(positionId != 0, "no position");

        _compound(); // fold pending fees/yield first so the split is fair to everyone

        (, , , , , , , uint128 totalLiq, , , ,) = pm.positions(positionId);
        uint128 removeLiq = uint128((uint256(totalLiq) * shareAmount) / totalShares);

        shares[msg.sender] -= shareAmount;
        totalShares        -= shareAmount;

        uint256 usdcStart = IERC20(USDC).balanceOf(address(this)); // baseline after compound

        (uint256 out0, uint256 out1) = pm.decreaseLiquidity(
            INonfungiblePositionManager.DecreaseLiquidityParams({
                tokenId:    positionId,
                liquidity:  removeLiq,
                amount0Min: 0,
                amount1Min: 0,
                deadline:   block.timestamp
            })
        );
        pm.collect(INonfungiblePositionManager.CollectParams({
            tokenId:    positionId,
            recipient:  address(this),
            amount0Max: uint128(out0),
            amount1Max: uint128(out1)
        }));

        // out0 = USDC (already in contract), out1 = Money -> redeem 1:1 to USDC
        if (out1 > 0) ICharityFund(MONEY).redeem(out1);

        uint256 usdcOut = IERC20(USDC).balanceOf(address(this)) - usdcStart; // = out0 + redeemed
        if (usdcOut > 0) _safeTransfer(USDC, msg.sender, usdcOut);
        emit Withdrawn(msg.sender, shareAmount, usdcOut);
    }

    // ═════════════════════════════════════════════════════════════════════
    //  Compound — fold trading fees + charity yield into the band (no swaps)
    // ═════════════════════════════════════════════════════════════════════

    function compound() external nonReentrant {
        _compound();
    }

    function _compound() internal {
        if (positionId == 0) return;

        // 1. Claim charity yield (paid in Money)
        if (yieldRegistered) {
            try ICharityFund(MONEY).claimV3Position(positionId) {} catch {}
        }
        // 2. Collect trading fees
        pm.collect(INonfungiblePositionManager.CollectParams({
            tokenId:    positionId,
            recipient:  address(this),
            amount0Max: type(uint128).max,
            amount1Max: type(uint128).max
        }));

        uint256 usdcBal  = IERC20(USDC).balanceOf(address(this));
        uint256 moneyBal = IERC20(MONEY).balanceOf(address(this));
        if (usdcBal == 0 && moneyBal == 0) return;

        // 3. Rebalance to the current range using 1:1 mint/redeem (no swaps)
        uint256 moneyFrac = _getToken1Fraction();
        if (moneyFrac == 0 && moneyBal > 0) {
            // below band: want all USDC -> redeem Money to USDC
            ICharityFund(MONEY).redeem(moneyBal);
        } else if (moneyFrac == 10000 && usdcBal > 0) {
            // above band: want all Money -> mint USDC to Money
            ICharityFund(MONEY).deposit(usdcBal);
        }
        // in band: add both as-is; PM takes what it needs, rest stays as dust for next compound

        usdcBal  = IERC20(USDC).balanceOf(address(this));
        moneyBal = IERC20(MONEY).balanceOf(address(this));
        if (usdcBal > 0 || moneyBal > 0) {
            _addLiquidity(usdcBal, moneyBal);
            emit Compounded(msg.sender, usdcBal, moneyBal);
        }
    }

    // ═════════════════════════════════════════════════════════════════════
    //  Yield registration (one-time, permissionless)
    // ═════════════════════════════════════════════════════════════════════

    function registerForYield() external {
        require(positionId != 0, "no position");
        require(!yieldRegistered, "already registered");
        ICharityFund(MONEY).registerV3Position(positionId);
        yieldRegistered = true;
    }

    // ═════════════════════════════════════════════════════════════════════
    //  Internal — tick fraction (bps of deposit that should be Money/token1)
    // ═════════════════════════════════════════════════════════════════════

    function _getToken1Fraction() internal view returns (uint256) {
        (, int24 currentTick,,,,,) = IUniswapV3Pool(pool).slot0();
        if (currentTick < tickLower) return 0;        // below band -> all USDC
        if (currentTick >= tickUpper) return 10000;   // above band -> all Money
        uint256 frac = uint256(int256(currentTick - tickLower)) * 10000
                     / uint256(int256(tickUpper - tickLower));
        if (frac < 100)  frac = 100;    // in band: V3 needs both sides — enforce 1% floor
        if (frac > 9900) frac = 9900;
        return frac;
    }

    // ═════════════════════════════════════════════════════════════════════
    //  Internal — add liquidity (mint once, then increase)
    // ═════════════════════════════════════════════════════════════════════

    function _addLiquidity(uint256 a0, uint256 a1) internal returns (uint128 liq) {
        if (positionId == 0) {
            uint256 tokenId;
            (tokenId, liq, ,) = pm.mint(INonfungiblePositionManager.MintParams({
                token0:         USDC,
                token1:         MONEY,
                fee:            poolFee,
                tickLower:      tickLower,
                tickUpper:      tickUpper,
                amount0Desired: a0,
                amount1Desired: a1,
                amount0Min:     0,
                amount1Min:     0,
                recipient:      address(this),
                deadline:       block.timestamp
            }));
            positionId = tokenId;
        } else {
            (liq, ,) = pm.increaseLiquidity(INonfungiblePositionManager.IncreaseLiquidityParams({
                tokenId:        positionId,
                amount0Desired: a0,
                amount1Desired: a1,
                amount0Min:     0,
                amount1Min:     0,
                deadline:       block.timestamp
            }));
        }
    }

    // ═════════════════════════════════════════════════════════════════════
    //  Internal — dust + safe token ops
    // ═════════════════════════════════════════════════════════════════════

    function _returnDust(address to, uint256 usdcBefore, uint256 moneyBefore) internal {
        uint256 usdcNow  = IERC20(USDC).balanceOf(address(this));
        uint256 moneyNow = IERC20(MONEY).balanceOf(address(this));
        if (usdcNow > usdcBefore)   _safeTransfer(USDC, to, usdcNow - usdcBefore);
        if (moneyNow > moneyBefore) _safeTransfer(MONEY, to, moneyNow - moneyBefore);
    }

    function _safeTransfer(address token, address to, uint256 amount) internal {
        (bool ok, bytes memory data) = token.call(
            abi.encodeWithSelector(IERC20.transfer.selector, to, amount)
        );
        require(ok && (data.length == 0 || abi.decode(data, (bool))), "transfer failed");
    }

    function _safeTransferFrom(address token, address from, address to, uint256 amount) internal {
        (bool ok, bytes memory data) = token.call(
            abi.encodeWithSelector(IERC20.transferFrom.selector, from, to, amount)
        );
        require(ok && (data.length == 0 || abi.decode(data, (bool))), "transferFrom failed");
    }

    // ═════════════════════════════════════════════════════════════════════
    //  Views (for the UI)
    // ═════════════════════════════════════════════════════════════════════

    function getInfo(address user) external view returns (
        uint256 userShares,
        uint256 userLiquidity,
        uint256 totalLiquidity
    ) {
        userShares = shares[user];
        if (positionId != 0) {
            (, , , , , , , uint128 liq, , , ,) = pm.positions(positionId);
            totalLiquidity = uint256(liq);
            if (totalShares > 0) {
                userLiquidity = (totalLiquidity * userShares) / totalShares;
            }
        }
    }

    /// @notice 0 = below band (all USDC), 1 = in band, 2 = above band (all Money)
    function rangeStatus() external view returns (uint8) {
        (, int24 currentTick,,,,,) = IUniswapV3Pool(pool).slot0();
        if (currentTick < tickLower) return 0;
        if (currentTick >= tickUpper) return 2;
        return 1;
    }

    function token1Fraction() external view returns (uint256) {
        return _getToken1Fraction();
    }

    function onERC721Received(address, address, uint256, bytes calldata) external pure returns (bytes4) {
        return this.onERC721Received.selector;
    }
}

project/contracts/TreePegVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/// @title TreePegVault — AZUSD peg defense powered by charity yield
/// @notice Deposit AZUSD or USDC -> one-sided sell wall at $1 on MfT/AZUSD pool.
///         Charity yield from MfT (Aave-backed) grows the wall over time.
///         Compound fees anytime. Withdraw anytime.

// ═══════════════════════════════════════════════════════════════════════════
//  Interfaces
// ═══════════════════════════════════════════════════════════════════════════

interface IERC20 {
    function approve(address spender, uint256 amount) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
    function transfer(address to, uint256 amount) external returns (bool);
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
}

interface ICharityFund {
    function redeem(uint256 amount) external;
    function registerV3Position(uint256 tokenId) external;
    function claimV3Position(uint256 tokenId) external;
}

interface INonfungiblePositionManager {
    struct MintParams {
        address token0; address token1; uint24 fee;
        int24 tickLower; int24 tickUpper;
        uint256 amount0Desired; uint256 amount1Desired;
        uint256 amount0Min; uint256 amount1Min;
        address recipient; uint256 deadline;
    }
    struct IncreaseLiquidityParams {
        uint256 tokenId;
        uint256 amount0Desired; uint256 amount1Desired;
        uint256 amount0Min; uint256 amount1Min;
        uint256 deadline;
    }
    struct DecreaseLiquidityParams {
        uint256 tokenId; uint128 liquidity;
        uint256 amount0Min; uint256 amount1Min;
        uint256 deadline;
    }
    struct CollectParams {
        uint256 tokenId; address recipient;
        uint128 amount0Max; uint128 amount1Max;
    }
    function mint(MintParams calldata) external payable returns (uint256, uint128, uint256, uint256);
    function increaseLiquidity(IncreaseLiquidityParams calldata) external payable returns (uint128, uint256, uint256);
    function decreaseLiquidity(DecreaseLiquidityParams calldata) external payable returns (uint256, uint256);
    function collect(CollectParams calldata) external payable returns (uint256, uint256);
    function positions(uint256) external view returns (
        uint96, address, address, address, uint24, int24, int24, uint128,
        uint256, uint256, uint128, uint128
    );
}

/// @dev SwapRouter02 on Base (no deadline field)
interface ISwapRouter02 {
    struct ExactInputSingleParams {
        address tokenIn; address tokenOut; uint24 fee;
        address recipient; uint256 amountIn;
        uint256 amountOutMinimum; uint160 sqrtPriceLimitX96;
    }
    function exactInputSingle(ExactInputSingleParams calldata) external payable returns (uint256);
}

// ═══════════════════════════════════════════════════════════════════════════
//  Contract
// ═══════════════════════════════════════════════════════════════════════════

contract TreePegVault {

    // ── Addresses ────────────────────────────────────────────────────────
    address public immutable AZUSD;   // token0, 18 dec
    address public immutable MFT;     // token1, 6 dec — CharityFund V4 deposit receipt
    address public immutable USDC;    // 6 dec

    INonfungiblePositionManager public immutable pm;
    ISwapRouter02 public immutable router;

    // ── Pool config ──────────────────────────────────────────────────────
    uint24 public immutable poolFee;   // fee tier for sell wall pool (e.g. 500 = 0.05%)
    uint24 public immutable swapFee;   // fee tier for USDC<>AZUSD swaps (e.g. 10000 = 1%)
    int24  public immutable tickLower; // sell wall lower bound (at $1 peg)
    int24  public immutable tickUpper; // sell wall upper bound

    // ── State ────────────────────────────────────────────────────────────
    uint256 public positionId;
    uint256 public totalShares;
    mapping(address => uint256) public shares;
    bool public yieldRegistered;

    // ── Reentrancy ───────────────────────────────────────────────────────
    uint256 private _locked = 1;
    modifier nonReentrant() {
        require(_locked == 1, "reentrant");
        _locked = 2;
        _;
        _locked = 1;
    }

    // ── Events ───────────────────────────────────────────────────────────
    event Deposited(address indexed user, uint256 shares, uint256 azusdAmount);
    event Withdrawn(address indexed user, uint256 shares, uint256 azusdOut);
    event Compounded(address indexed caller, uint256 azusdAdded, uint256 mftAdded);

    // ═════════════════════════════════════════════════════════════════════
    //  Constructor
    // ═════════════════════════════════════════════════════════════════════

    constructor(
        address _azusd,
        address _mft,
        address _usdc,
        address _pm,
        address _router,
        uint24  _poolFee,
        uint24  _swapFee,
        int24   _tickLower,
        int24   _tickUpper
    ) {
        require(_azusd < _mft, "token order: azusd must be token0");

        AZUSD   = _azusd;
        MFT     = _mft;
        USDC    = _usdc;
        pm      = INonfungiblePositionManager(_pm);
        router  = ISwapRouter02(_router);
        poolFee = _poolFee;
        swapFee = _swapFee;
        tickLower = _tickLower;
        tickUpper = _tickUpper;

        // Max-approve infrastructure (one-time, immutable targets)
        IERC20(_azusd).approve(_pm, type(uint256).max);
        IERC20(_azusd).approve(_router, type(uint256).max);
        IERC20(_mft).approve(_pm, type(uint256).max);
        IERC20(_usdc).approve(_router, type(uint256).max);
    }

    // ═════════════════════════════════════════════════════════════════════
    //  Deposit — put AZUSD on the $1 sell wall
    // ═════════════════════════════════════════════════════════════════════

    /// @notice Deposit AZUSD — goes directly onto sell wall at $1
    function depositAZUSD(uint256 amount) external nonReentrant {
        require(amount > 0, "zero");
        _safeTransferFrom(AZUSD, msg.sender, address(this), amount);

        uint128 liq = _addLiquidity(amount, 0);
        require(liq > 0, "sell wall full: AZUSD at or above peg");

        shares[msg.sender] += uint256(liq);
        totalShares += uint256(liq);
        emit Deposited(msg.sender, uint256(liq), amount);
    }

    /// @notice Deposit USDC — buys AZUSD, puts on sell wall
    function depositUSDC(uint256 amount) external nonReentrant {
        require(amount > 0, "zero");
        _safeTransferFrom(USDC, msg.sender, address(this), amount);

        // Swap USDC -> AZUSD via existing USDC/AZUSD pool
        uint256 azusdOut = router.exactInputSingle(
            ISwapRouter02.ExactInputSingleParams({
                tokenIn:           USDC,
                tokenOut:          AZUSD,
                fee:               swapFee,
                recipient:         address(this),
                amountIn:          amount,
                amountOutMinimum:  0,
                sqrtPriceLimitX96: 0
            })
        );

        uint128 liq = _addLiquidity(azusdOut, 0);
        require(liq > 0, "sell wall full: AZUSD at or above peg");

        shares[msg.sender] += uint256(liq);
        totalShares += uint256(liq);
        emit Deposited(msg.sender, uint256(liq), azusdOut);
    }

    // ═════════════════════════════════════════════════════════════════════
    //  Withdraw — get AZUSD and/or USDC back
    // ═════════════════════════════════════════════════════════════════════

    /// @notice Withdraw your share. Always returns AZUSD.
    function withdraw(uint256 shareAmount) external nonReentrant {
        require(shareAmount > 0 && shareAmount <= shares[msg.sender], "bad shares");
        require(positionId != 0, "no position");

        // Compound outstanding fees first (clean math)
        _compound();

        (, , , , , , , uint128 totalLiq, , , ,) = pm.positions(positionId);
        uint128 removeLiq = uint128((uint256(totalLiq) * shareAmount) / totalShares);

        shares[msg.sender] -= shareAmount;
        totalShares -= shareAmount;

        // Remove liquidity
        (uint256 out0, uint256 out1) = pm.decreaseLiquidity(
            INonfungiblePositionManager.DecreaseLiquidityParams({
                tokenId:    positionId,
                liquidity:  removeLiq,
                amount0Min: 0,
                amount1Min: 0,
                deadline:   block.timestamp
            })
        );

        // Collect only the removed amounts (leave fees for future compound)
        pm.collect(INonfungiblePositionManager.CollectParams({
            tokenId:    positionId,
            recipient:  address(this),
            amount0Max: uint128(out0),
            amount1Max: uint128(out1)
        }));

        uint256 azusdTotal = out0; // AZUSD from position directly

        // If wall was crossed, position holds MfT. Convert MfT -> USDC -> AZUSD
        if (out1 > 0) {
            ICharityFund(MFT).redeem(out1);
            uint256 usdcBal = IERC20(USDC).balanceOf(address(this));
            if (usdcBal > 0) {
                azusdTotal += router.exactInputSingle(
                    ISwapRouter02.ExactInputSingleParams({
                        tokenIn:           USDC,
                        tokenOut:          AZUSD,
                        fee:               swapFee,
                        recipient:         address(this),
                        amountIn:          usdcBal,
                        amountOutMinimum:  0,
                        sqrtPriceLimitX96: 0
                    })
                );
            }
        }

        if (azusdTotal > 0) _safeTransfer(AZUSD, msg.sender, azusdTotal);
        emit Withdrawn(msg.sender, shareAmount, azusdTotal);
    }

    // ═════════════════════════════════════════════════════════════════════
    //  Compound — reinvest fees + charity yield into deeper wall
    // ═════════════════════════════════════════════════════════════════════

    /// @notice Compound trading fees and charity yield. Anyone can call.
    function compound() external nonReentrant {
        _compound();
    }

    function _compound() internal {
        if (positionId == 0) return;

        // 1. Claim charity yield if registered (MfT sent to this contract)
        if (yieldRegistered) {
            try ICharityFund(MFT).claimV3Position(positionId) {} catch {}
        }

        // 2. Collect trading fees from V3 position
        pm.collect(INonfungiblePositionManager.CollectParams({
            tokenId:    positionId,
            recipient:  address(this),
            amount0Max: type(uint128).max,
            amount1Max: type(uint128).max
        }));

        // 3. Add total balances back to position
        //    PM takes what it can based on current price & tick range.
        //    Excess stays in contract for next compound.
        uint256 azusdBal = IERC20(AZUSD).balanceOf(address(this));
        uint256 mftBal   = IERC20(MFT).balanceOf(address(this));

        if (azusdBal == 0 && mftBal == 0) return;

        _addLiquidity(azusdBal, mftBal);
        emit Compounded(msg.sender, azusdBal, mftBal);
    }

    // ═════════════════════════════════════════════════════════════════════
    //  Yield Registration — one-time setup for charity yield
    // ═════════════════════════════════════════════════════════════════════

    /// @notice Register position with MfT CharityFund for yield accrual. Anyone can call once.
    function registerForYield() external {
        require(positionId != 0, "no position");
        require(!yieldRegistered, "already registered");
        ICharityFund(MFT).registerV3Position(positionId);
        yieldRegistered = true;
    }

    // ═════════════════════════════════════════════════════════════════════
    //  Internal
    // ═════════════════════════════════════════════════════════════════════

    function _addLiquidity(uint256 a0, uint256 a1) internal returns (uint128 liq) {
        if (positionId == 0) {
            uint256 tokenId;
            (tokenId, liq, ,) = pm.mint(INonfungiblePositionManager.MintParams({
                token0:         AZUSD,
                token1:         MFT,
                fee:            poolFee,
                tickLower:      tickLower,
                tickUpper:      tickUpper,
                amount0Desired: a0,
                amount1Desired: a1,
                amount0Min:     0,
                amount1Min:     0,
                recipient:      address(this),
                deadline:       block.timestamp
            }));
            positionId = tokenId;
        } else {
            (liq, ,) = pm.increaseLiquidity(INonfungiblePositionManager.IncreaseLiquidityParams({
                tokenId:        positionId,
                amount0Desired: a0,
                amount1Desired: a1,
                amount0Min:     0,
                amount1Min:     0,
                deadline:       block.timestamp
            }));
        }
    }

    // ── Safe token ops (handles non-standard returns) ────────────────────

    function _safeTransfer(address token, address to, uint256 amount) internal {
        (bool ok, bytes memory data) = token.call(
            abi.encodeWithSelector(IERC20.transfer.selector, to, amount)
        );
        require(ok && (data.length == 0 || abi.decode(data, (bool))), "transfer failed");
    }

    function _safeTransferFrom(address token, address from, address to, uint256 amount) internal {
        (bool ok, bytes memory data) = token.call(
            abi.encodeWithSelector(IERC20.transferFrom.selector, from, to, amount)
        );
        require(ok && (data.length == 0 || abi.decode(data, (bool))), "transferFrom failed");
    }

    // ═════════════════════════════════════════════════════════════════════
    //  Views
    // ═════════════════════════════════════════════════════════════════════

    function getPosition() external view returns (uint128 liquidity, uint128 owed0, uint128 owed1) {
        if (positionId == 0) return (0, 0, 0);
        (, , , , , , , liquidity, , , owed0, owed1) = pm.positions(positionId);
    }

    function onERC721Received(address, address, uint256, bytes calldata) external pure returns (bytes4) {
        return this.onERC721Received.selector;
    }
}

